Implementasi Observer Pattern yang robust untuk lingkungan produksi. Menggunakan `abc` untuk enforce interface dan `threading.Lock` untuk concurrency safety.

```python
from abc import ABC, abstractmethod
from typing import List, Any
import threading
import logging

# Konfigurasi Logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger("ObserverPattern")

class IObserver(ABC):
    @abstractmethod
    def update(self, subject: 'Subject') -> None:
        pass

class ISubject(ABC):
    @abstractmethod
    def attach(self, observer: IObserver) -> None:
        pass

    @abstractmethod
    def detach(self, observer: IObserver) -> None:
        pass

    @abstractmethod
    def notify(self) -> None:
        pass

class Subject(ISubject):
    def __init__(self) -> None:
        self._observers: List[IObserver] = []
        self._lock = threading.Lock()
        self._state: Any = None

    def attach(self, observer: IObserver) -> None:
        with self._lock:
            if observer not in self._observers:
                self._observers.append(observer)
                logger.info("Observer attached successfully.")

    def detach(self, observer: IObserver) -> None:
        with self._lock:
            if observer in self._observers:
                self._observers.remove(observer)
                logger.info("Observer detached successfully.")

    def set_state(self, state: Any) -> None:
        self._state = state
        self.notify()

    def get_state(self) -> Any:
        return self._state

    def notify(self) -> None:
        with self._lock:
            # Copy list to avoid modification during iteration
            observers = self._observers[:] 

        for observer in observers:
            try:
                observer.update(self)
            except Exception as e:
                logger.error(f"Observer update failed: {e}")

class ConcreteObserver(IObserver):
    def __init__(self, name: str) -> None:
        self.name = name

    def update(self, subject: Subject) -> None:
        state = subject.get_state()
        logger.info(f"[{self.name}] Received update. New State: {state}")

# Usage Example
if __name__ == "__main__":
    subject = Subject()
    obs1 = ConcreteObserver("SecurityMonitor")
    obs2 = ConcreteObserver("LogAnalyzer")

    subject.attach(obs1)
    subject.attach(obs2)

    # Trigger event
    subject.set_state({"alert": "SQL Injection Attempt", "ip": "192.168.1.10"})

    subject.detach(obs1)
    subject.set_state({"status": "Normal"})
```

### Catatan Teknis:
1.  **Thread Safety**: Menggunakan `threading.Lock` pada metode kritis (`attach`, `detach`, `notify`). Wajib untuk lingkungan server multithread (seperti Flask/Gunicorn worker).
2.  **Error Handling**: `try-except` blok di dalam `notify` mencegah satu observer yang error menghentikan notifikasi ke observer lain.
3.  **Type Hinting**: Menggunakan `typing` untuk maintainability kode dan deteksi dini bugs.
4.  **Logging**: Jangan gunakan `print` untuk produksi. Gunakan `logging` untuk audit trail.

Pastikan validasi input dilakukan sebelum `set_state` jika data berasal dari user eksternal untuk mencegah injection melalui payload event.
